// src/components/Layout/index.jsx

import React from 'react';
import { Outlet } from 'react-router-dom';
import Header from '../Header'; // Убедитесь, что этот путь верен
import Footer from '../Footer'; // Убедитесь, что этот путь верен
import styles from './Layout.module.css'; // Создайте этот файл стилей

const Layout = () => {
  return (
    <div className={styles.layout}>
      <Header />
      <main className={styles.content}>
        <Outlet /> 
      </main>
      <Footer />
    </div>
  );
};

export default Layout;
